// mm/src/api/listDocuments.js
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_BASE_URL || '';
const DEFAULT_LIST_DOCS_URL =
  'https://manuscriptmagic.fowkes.xyz/services/listDocuments.php';

function getListDocumentsUrl() {
  return API_BASE ? `${API_BASE}/documents` : DEFAULT_LIST_DOCS_URL;
}

function getAccessToken() {
  return localStorage.getItem('mm_accessToken') || '';
}

export const listDocuments = () => {
  const accessToken = getAccessToken();


  if (!API_BASE) {
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({
          data: {
            success: true,
            message: 'Mock listDocuments success',
            documents: [
              {
                documentId: 'mock_doc_1001',
                filename: 'MyBook.docx',
                filePath: '/mock/docs/MyBook.docx',
                uploadedAt: new Date().toISOString(),
              },
              {
                documentId: 'mock_doc_1002',
                filename: 'Cover.png',
                filePath: '/mock/docs/Cover.png',
                uploadedAt: new Date().toISOString(),
              },
            ],
          },
        });
      }, 300);
    });
  }

  const url = getListDocumentsUrl();

  return axios.get(url, {
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${accessToken}`,
    },
  });
};
